export declare const widgetStyles = "\n:host {\n  all: initial;\n  color-scheme: light;\n}\n*, *::before, *::after {\n  box-sizing: border-box;\n}\n.oa-shell {\n  position: fixed;\n  inset: auto 24px 24px auto;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n  color: #0f172a;\n  z-index: var(--oa-z-index, 2147483000);\n}\n.oa-shell[data-position=\"bottom-left\"] {\n  left: 24px;\n  right: auto;\n}\n.oa-launcher {\n  border: 0;\n  border-radius: 999px;\n  background: var(--oa-accent, #0f5bd8);\n  color: #ffffff;\n  min-width: 56px;\n  min-height: 56px;\n  padding: 0 18px;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n  cursor: pointer;\n  font: 600 14px/1 system-ui, sans-serif;\n}\n.oa-launcher:focus-visible,\n.oa-panel button:focus-visible,\n.oa-panel input:focus-visible,\n.oa-panel select:focus-visible {\n  outline: 3px solid #ff9f0a;\n  outline-offset: 2px;\n}\n.oa-panel {\n  width: min(360px, calc(100vw - 24px));\n  margin-top: 12px;\n  border: 1px solid #d7dee8;\n  border-radius: 18px;\n  background: #ffffff;\n  display: none;\n  overflow: hidden;\n}\n.oa-panel[data-open=\"true\"] {\n  display: block;\n}\n.oa-header {\n  padding: 16px 18px 12px;\n  border-bottom: 1px solid #e2e8f0;\n}\n.oa-title {\n  margin: 0;\n  font: 700 16px/1.3 system-ui, sans-serif;\n}\n.oa-description {\n  margin: 6px 0 0;\n  color: #475569;\n  font: 400 13px/1.5 system-ui, sans-serif;\n}\n.oa-body {\n  padding: 10px 14px 14px;\n  max-height: min(70vh, 540px);\n  overflow: auto;\n}\n.oa-group {\n  padding: 10px 4px;\n  border-bottom: 1px solid #edf2f7;\n}\n.oa-group:last-child {\n  border-bottom: 0;\n}\n.oa-group-title {\n  margin: 0 0 10px;\n  color: #334155;\n  font: 700 12px/1.4 system-ui, sans-serif;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n}\n.oa-row {\n  display: grid;\n  grid-template-columns: 1fr auto;\n  gap: 12px;\n  align-items: center;\n  margin: 8px 0;\n}\n.oa-label {\n  font: 500 14px/1.4 system-ui, sans-serif;\n}\n.oa-hint {\n  color: #64748b;\n  font: 400 12px/1.4 system-ui, sans-serif;\n}\n.oa-toggle {\n  inline-size: 18px;\n  block-size: 18px;\n}\n.oa-range {\n  width: 132px;\n}\n.oa-actions {\n  display: flex;\n  gap: 8px;\n  padding-top: 10px;\n}\n.oa-button {\n  border: 1px solid #cbd5e1;\n  background: #f8fafc;\n  color: #0f172a;\n  border-radius: 12px;\n  padding: 10px 12px;\n  cursor: pointer;\n  font: 600 13px/1 system-ui, sans-serif;\n}\n.oa-live {\n  position: absolute;\n  inline-size: 1px;\n  block-size: 1px;\n  overflow: hidden;\n  clip-path: inset(50%);\n}\n.oa-issues {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.oa-issue {\n  border: 1px solid #e2e8f0;\n  border-radius: 12px;\n  padding: 10px;\n  margin: 8px 0;\n}\n.oa-issue strong {\n  display: block;\n  margin-bottom: 4px;\n}\n@media (prefers-reduced-motion: no-preference) {\n  .oa-panel {\n    transform-origin: bottom right;\n    animation: oa-fade-in 160ms ease-out;\n  }\n}\n@keyframes oa-fade-in {\n  from {\n    opacity: 0;\n    transform: translateY(6px) scale(0.98);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0) scale(1);\n  }\n}\n@media (max-width: 640px) {\n  .oa-shell,\n  .oa-shell[data-position=\"bottom-left\"] {\n    left: 12px;\n    right: 12px;\n    bottom: 12px;\n  }\n  .oa-panel {\n    width: 100%;\n  }\n  .oa-launcher {\n    width: 100%;\n  }\n}\n";
